import React, { useState, useEffect } from 'react';
import { View, Text, TouchableOpacity, Alert } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import * as Keychain from 'react-native-keychain';

const OAuthClient = () => {
  const [accessToken, setAccessToken] = useState(null);
  const [refreshToken, setRefreshToken] = useState(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  const CLIENT_ID = 'your_client_id';
  const CLIENT_SECRET = 'your_client_secret';
  const AUTHORIZATION_ENDPOINT = 'https://your-oauth-server.com/oauth/authorize';
  const TOKEN_ENDPOINT = 'https://your-oauth-server.com/oauth/token';
  const REDIRECT_URI = 'your-app://oauth/callback';

  useEffect(() => {
    const loadTokens = async () => {
      try {
        const storedAccessToken = await AsyncStorage.getItem('access_token');
        const storedRefreshToken = await AsyncStorage.getItem('refresh_token');
        
        if (storedAccessToken && storedRefreshToken) {
          setAccessToken(storedAccessToken);
          setRefreshToken(storedRefreshToken);
          setIsAuthenticated(true);
        }
      } catch (error) {
        console.error('Error loading tokens:', error);
      }
    };

    loadTokens();
  }, []);

  const handleLogin = async () => {
    try {
      const authUrl = `${AUTHORIZATION_ENDPOINT}?client_id=${CLIENT_ID}&redirect_uri=${REDIRECT_URI}&response_type=code&scope=read`;
      // Open authUrl in browser or in-app browser
      // This would typically use a library like react-native-inappbrowser-reborn
      // For demo purposes, we'll simulate the flow
      console.log('Open this URL:', authUrl);
    } catch (error) {
      Alert.alert('Login Error', error.message);
    }
  };

  const exchangeCodeForToken = async (code) => {
    try {
      const response = await fetch(TOKEN_ENDPOINT, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
          'Authorization': `Basic ${btoa(`${CLIENT_ID}:${CLIENT_SECRET}`)}`
        },
        body: `grant_type=authorization_code&code=${code}&redirect_uri=${REDIRECT_URI}`
      });

      const data = await response.json();
      
      if (data.access_token && data.refresh_token) {
        await AsyncStorage.setItem('access_token', data.access_token);
        await AsyncStorage.setItem('refresh_token', data.refresh_token);
        
        setAccessToken(data.access_token);
        setRefreshToken(data.refresh_token);
        setIsAuthenticated(true);
      }
    } catch (error) {
      console.error('Token exchange error:', error);
    }
  };

  const refreshAccessToken = async () => {
    if (!refreshToken) return;

    try {
      const response = await fetch(TOKEN_ENDPOINT, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
          'Authorization': `Basic ${btoa(`${CLIENT_ID}:${CLIENT_SECRET}`)}`
        },
        body: `grant_type=refresh_token&refresh_token=${refreshToken}`
      });

      const data = await response.json();
      
      if (data.access_token) {
        await AsyncStorage.setItem('access_token', data.access_token);
        setAccessToken(data.access_token);
      }
    } catch (error) {
      console.error('Token refresh error:', error);
    }
  };

  const handleLogout = async () => {
    try {
      await AsyncStorage.removeItem('access_token');
      await AsyncStorage.removeItem('refresh_token');
      setAccessToken(null);
      setRefreshToken(null);
      setIsAuthenticated(false);
    } catch (error) {
      console.error('Logout error:', error);
    }
  };

  const makeAuthenticatedRequest = async (url) => {
    if (!accessToken) return null;

    try {
      const response = await fetch(url, {
        headers: {
          'Authorization': `Bearer ${accessToken}`
        }
      });

      if (response.status === 401) {
        await refreshAccessToken();
        // Retry the request with new token
        const retryResponse = await fetch(url, {
          headers: {
            'Authorization': `Bearer ${accessToken}`
          }
        });
        return retryResponse.json();
      }

      return response.json();
    } catch (error) {
      console.error('Request error:', error);
      return null;
    }
  };

  return (
    <View style={{ flex: 1, justifyContent: 'center', padding: 20 }}>
      {!isAuthenticated ? (
        <TouchableOpacity onPress={handleLogin} style={{ padding: 15, backgroundColor: '#007AFF', borderRadius: 5 }}>
          <Text style={{ color: 'white', textAlign: 'center' }}>Login with OAuth</Text>
        </TouchableOpacity>
      ) : (
        <View>
          <Text>Authenticated</Text>
          <TouchableOpacity onPress={handleLogout} style={{ padding: 15, backgroundColor: '#FF3B30', borderRadius: 5, marginTop: 10 }}>
            <Text style={{ color: 'white', textAlign: 'center' }}>Logout</Text>
          </TouchableOpacity>
        </View>
      )}
    </View>
  );
};

export default OAuthClient;